const forms = $item(0).$node["Zendesk - Get Ticket Forms"].json.ticket_forms || [];

const featureMap = {
  "DrFirst Order Form": { field_id: 22937458172699, field_title: "DrFirst Section/Feature" },
  "EMR Default Form": { field_id: 1900003693164, field_title: "EMR Section/Feature" },
  "Lab Support Form": { field_id: 32729688213531, field_title: "Labs Section/Feature" },
  "Billing Form": { field_id: 1260824167749, field_title: "Billing Section/Feature" },
  "CRM Form": { field_id: 1900003692984, field_title: "CRM Section/Feature" },
  "Kipu RCM Support": { field_id: 13443937881883, field_title: "RCM Section/Feature" }
};

const activeForms = forms
  .filter(f => f.active && f.name !== "Zendesk Admin Test")
  .map(f => ({
    id: f.id,
    name: f.name
  }));

const formFeatureMapping = {};
for (const form of activeForms) {
  if (featureMap[form.name]) {
    formFeatureMapping[form.name] = {
      field_id: featureMap[form.name].field_id,
      field_title: featureMap[form.name].field_title
    };
  }
}

return [{
  json: {
    source: "zendesk",
    fetched_at: new Date().toISOString(),
    ticket_forms: activeForms,
    form_feature_mapping: formFeatureMapping
  }
}];

const body = $json.body || $json;

const formId = body.form_id;
const formName = body.form_name;
const dateFrom = body.date_from;
const dateTo = body.date_to;

if (!formId || !dateFrom || !dateTo) {
  throw new Error("form_id, date_from, and date_to are required");
}

const query = `type:ticket ticket_form_id:${formId} created>${dateFrom} created<${dateTo}`;

return [
  {
    json: {
      form_id: formId,
      form_name: formName,
      date_from: dateFrom,
      date_to: dateTo,
      zendesk_query: query
    }
  }
];

const request = $item(0).$node["Prepare Preview Request"].json;

return [{
  json: {
    source: "zendesk",
    filters: {
      form_id: request.form_id,
      form_name: request.form_name,
      date_from: request.date_from,
      date_to: request.date_to,
      query_used: request.zendesk_query
    },
    total_found: $json.count || 0
  }
}];

const body = $json.body || $json;

const analysis_batch_id = body.analysis_batch_id || null;
const form_id = body.form_id;
const form_name = body.form_name || null;
const date_from = body.date_from;
const date_to = body.date_to;
const limit = Number(body.limit || 10);

if (!form_id || !date_from || !date_to) {
  throw new Error('form_id, date_from, and date_to are required');
}

const zendesk_query = `type:ticket ticket_form_id:${form_id} created>${date_from} created<${date_to}`;

return [{
  json: {
    analysis_batch_id,
    form_id,
    form_name,
    date_from,
    date_to,
    limit,
    zendesk_query
  }
}];

const request = $('Prepare Analysis Request').first().json;
const tickets = $json.results || [];

return tickets.map(t => ({
  json: {
    analysis_batch_id: request.analysis_batch_id,
    form_id: request.form_id,
    form_name: request.form_name,
    date_from: request.date_from,
    date_to: request.date_to,
    ticket_id: t.id,
    subject: t.subject || '',
    requester_id: t.requester_id || null,
    assignee_id: t.assignee_id || null,
    created_at: t.created_at || null,
    updated_at: t.updated_at || null,
    status: t.status || null,
    tags: t.tags || []
  }
}));

const ticket = $('Build Ticket Items').item.json;
const comments = $json.comments || [];

function getRole(comment) {
  if (comment.author_id === ticket.requester_id) return 'customer';
  if (comment.author_id === ticket.assignee_id) return 'assignee';
  if (comment.public === false) return 'internal';
  return 'other_agent';
}

const structuredComments = comments
  .filter(c => c.public !== false) // keep public comments only
  .slice(-5) // keep last 5 comments
  .map(c => ({
    author_id: c.author_id,
    role: getRole(c),
    public: c.public,
    created_at: c.created_at,
    body: (c.body || c.plain_body || '').slice(0, 1200) // cap each comment
  }));

return {
  json: {
    analysis_batch_id: ticket.analysis_batch_id,
    form_id: ticket.form_id,
    form_name: ticket.form_name,
    date_from: ticket.date_from,
    date_to: ticket.date_to,
    ticket_id: ticket.ticket_id,
    subject: ticket.subject,
    requester_id: ticket.requester_id,
    assignee_id: ticket.assignee_id,
    created_at: ticket.created_at,
    updated_at: ticket.updated_at,
    status: ticket.status,
    tags: ticket.tags,
    comment_count: structuredComments.length,
    first_comment_at: structuredComments[0]?.created_at || null,
    last_comment_at: structuredComments[structuredComments.length - 1]?.created_at || null,
    comments: structuredComments
  }
};

const batch = $json;

const results = Array.isArray(batch.normalized_results)
  ? batch.normalized_results
  : [];

const opportunity_groups = Array.isArray(batch.opportunity_groups)
  ? batch.opportunity_groups
  : [];

const heatmap_rows = Array.isArray(batch.heatmap_rows)
  ? batch.heatmap_rows
  : [];

const rootCauseCountsMap = new Map();
const tagCountsMap = new Map();

let kbOpportunityCount = 0;
let automationOpportunityCount = 0;

let totalPromptTokens = 0;
let totalCompletionTokens = 0;
let totalTokens = 0;

for (const row of results) {
  const category = row.root_cause_category || 'Unclear';
  rootCauseCountsMap.set(
    category,
    (rootCauseCountsMap.get(category) || 0) + 1
  );

  const tags = Array.isArray(row.normalized_tags)
    ? row.normalized_tags
    : String(row.key_tags || '')
        .split(',')
        .map(t => t.trim())
        .filter(Boolean);

  for (const tag of tags) {
    tagCountsMap.set(tag, (tagCountsMap.get(tag) || 0) + 1);
  }

  if (row.knowledge_base_opportunity === 'Yes') {
    kbOpportunityCount += 1;
  }

  if (row.automation_opportunity === 'Yes') {
    automationOpportunityCount += 1;
  }

  totalPromptTokens += Number(row.prompt_tokens || 0);
  totalCompletionTokens += Number(row.completion_tokens || 0);
  totalTokens += Number(row.total_tokens || 0);
}

totalPromptTokens += Number(batch.llm2_prompt_tokens || 0);
totalCompletionTokens += Number(batch.llm2_completion_tokens || 0);
totalTokens += Number(batch.llm2_total_tokens || 0);

const root_cause_category_counts = Array.from(rootCauseCountsMap.entries())
  .map(([category, count]) => ({
    category,
    count
  }))
  .sort((a, b) => {
    if (b.count !== a.count) return b.count - a.count;
    return a.category.localeCompare(b.category);
  });

const top_tags = Array.from(tagCountsMap.entries())
  .map(([tag, count]) => ({
    tag,
    count
  }))
  .sort((a, b) => {
    if (b.count !== a.count) return b.count - a.count;
    return a.tag.localeCompare(b.tag);
  })
  .slice(0, 10);

const sorted_opportunity_groups = [...opportunity_groups].sort((a, b) => {
  if ((b.linked_ticket_count || 0) !== (a.linked_ticket_count || 0)) {
    return (b.linked_ticket_count || 0) - (a.linked_ticket_count || 0);
  }
  return String(a.title || '').localeCompare(String(b.title || ''));
});

const sorted_heatmap_rows = [...heatmap_rows].sort((a, b) => {
  const categoryCompare = String(a.root_cause_category || '').localeCompare(
    String(b.root_cause_category || '')
  );

  if (categoryCompare !== 0) return categoryCompare;

  return String(a.form_name || '').localeCompare(String(b.form_name || ''));
});

return [
  {
    json: {
      analysis_batch_id: batch.analysis_batch_id,
      form_id: batch.form_id,
      form_name: batch.form_name,
      date_from: batch.date_from,
      date_to: batch.date_to,
      total_tickets: Number(batch.total_tickets || results.length),
      analyzed_count: Number(batch.analyzed_count || results.length),

      batch_summary: {
        kb_opportunity_count: kbOpportunityCount,
        automation_opportunity_count: automationOpportunityCount,
        root_cause_category_counts,
        top_tags,
        total_prompt_tokens: totalPromptTokens,
        total_completion_tokens: totalCompletionTokens,
        total_tokens: totalTokens
      },

      opportunity_groups: sorted_opportunity_groups,
      heatmap_rows: sorted_heatmap_rows,

      results: results.map(r => ({
        ticket_id: r.ticket_id,
        issue_summary: r.issue_summary,
        root_cause_category: r.root_cause_category,
        root_cause_detail: r.root_cause_detail,
        customer_goal: r.customer_goal,
        resolution_status: r.resolution_status,
        agent_performance_notes: r.agent_performance_notes,
        agent_improvement_opportunities: r.agent_improvement_opportunities,
        knowledge_base_opportunity: r.knowledge_base_opportunity,
        knowledge_base_opportunity_detail: r.knowledge_base_opportunity_detail,
        automation_opportunity: r.automation_opportunity,
        automation_opportunity_detail: r.automation_opportunity_detail,
        suggested_opportunity_type: r.suggested_opportunity_type,
        opportunity_type: r.opportunity_type,
        key_tags: r.key_tags,
        prompt_tokens: Number(r.prompt_tokens || 0),
        completion_tokens: Number(r.completion_tokens || 0),
        total_tokens: Number(r.total_tokens || 0),
        created_at: r.created_at
      }))
    }
  }
];

const raw = $json.output_text || $json.text || '';
const text = String(raw).replace(/\\n/g, '\n');
const source = $('Build Analysis Input').item.json;

function extract(label, nextLabels = []) {
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const nextPattern = nextLabels
    .map(l => l.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
    .join('|');

  const regex = nextPattern
    ? new RegExp(`${escapedLabel}\\s*([\\s\\S]*?)(?=\\n(?:${nextPattern})\\s*|$)`, 'i')
    : new RegExp(`${escapedLabel}\\s*([\\s\\S]*)$`, 'i');

  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

function cleanText(value) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizeText(value) {
  let v = cleanText(value);

  v = v.replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, '[REDACTED_EMAIL]');
  v = v.replace(/https?:\/\/\S+/gi, '[REDACTED_URL]');
  v = v.replace(/\+?\d[\d\-\(\) ]{7,}\d/g, '[REDACTED_PHONE]');
  v = v.replace(/\b\d{5,}\b/g, '[REDACTED_NUMBER]');

  return v;
}

function normalizeYesNo(value) {
  const v = cleanText(value).toLowerCase();
  if (v === 'yes' || v.startsWith('yes')) return 'Yes';
  if (v === 'no' || v.startsWith('no')) return 'No';
  return 'Unclear';
}

function normalizeStatus(value) {
  const v = cleanText(value).toLowerCase();
  if (v === 'resolved' || v.startsWith('resolved')) return 'Resolved';
  if (v === 'not resolved' || v.startsWith('not resolved') || v.startsWith('unresolved')) return 'Not Resolved';
  if (v === 'pending customer action' || v.startsWith('pending customer action')) return 'Pending Customer Action';
  return 'Unclear';
}

const allowedCategories = new Set([
  'Missing client data',
  'Missing required credentials',
  'Access / permissions issue',
  'Configuration / setup issue',
  'Process / workflow gap',
  'User error / misunderstanding',
  'Knowledge / training gap',
  'Software defect / bug',
  'Software usability / UI friction',
  'Integration / third-party dependency',
  'Performance / timeout / latency',
  'Communication / follow-up breakdown',
  'Policy / compliance requirement',
  'Duplicate / merged / cross-ticket confusion',
  'Unclear'
]);

function normalizeCategory(value) {
  const cleaned = sanitizeText(value);
  if (allowedCategories.has(cleaned)) return cleaned;

  const lower = cleaned.toLowerCase();
  const map = [
    ['missing client data', 'Missing client data'],
    ['missing required credentials', 'Missing required credentials'],
    ['access', 'Access / permissions issue'],
    ['permission', 'Access / permissions issue'],
    ['configuration', 'Configuration / setup issue'],
    ['setup', 'Configuration / setup issue'],
    ['workflow', 'Process / workflow gap'],
    ['process', 'Process / workflow gap'],
    ['user error', 'User error / misunderstanding'],
    ['misunderstanding', 'User error / misunderstanding'],
    ['training', 'Knowledge / training gap'],
    ['knowledge', 'Knowledge / training gap'],
    ['bug', 'Software defect / bug'],
    ['defect', 'Software defect / bug'],
    ['usability', 'Software usability / UI friction'],
    ['ui', 'Software usability / UI friction'],
    ['integration', 'Integration / third-party dependency'],
    ['third-party', 'Integration / third-party dependency'],
    ['latency', 'Performance / timeout / latency'],
    ['timeout', 'Performance / timeout / latency'],
    ['performance', 'Performance / timeout / latency'],
    ['communication', 'Communication / follow-up breakdown'],
    ['follow-up', 'Communication / follow-up breakdown'],
    ['policy', 'Policy / compliance requirement'],
    ['compliance', 'Policy / compliance requirement'],
    ['duplicate', 'Duplicate / merged / cross-ticket confusion'],
    ['merged', 'Duplicate / merged / cross-ticket confusion'],
    ['unclear', 'Unclear']
  ];

  for (const [needle, normalized] of map) {
    if (lower.includes(needle)) return normalized;
  }

  return 'Unclear';
}

function normalizeOpportunityType(value) {
  const cleaned = sanitizeText(value);
  const lower = cleaned.toLowerCase();

  if (cleaned === 'Knowledge Base') return 'Knowledge Base';
  if (cleaned === 'Process Update') return 'Process Update';
  if (cleaned === 'Agent Training') return 'Agent Training';
  if (cleaned === 'Product Improvement') return 'Product Improvement';

  if (lower.includes('knowledge') || lower.includes('documentation') || lower.includes('kb')) {
    return 'Knowledge Base';
  }
  if (lower.includes('process') || lower.includes('workflow') || lower.includes('routing') || lower.includes('handoff')) {
    return 'Process Update';
  }
  if (lower.includes('agent') || lower.includes('training') || lower.includes('coaching') || lower.includes('follow-up')) {
    return 'Agent Training';
  }

  return 'Product Improvement';
}

function cleanTags(value) {
  return sanitizeText(value)
    .split(',')
    .map(t => t.trim())
    .filter(Boolean)
    .slice(0, 5)
    .join(', ');
}

const issue_summary = sanitizeText(
  extract('Issue Summary:', ['Root Cause Category:'])
);

const root_cause_category = normalizeCategory(
  extract('Root Cause Category:', ['Root Cause Detail:'])
);

const root_cause_detail = sanitizeText(
  extract('Root Cause Detail:', ['Customer Goal:'])
) || 'Unclear';

const customer_goal = sanitizeText(
  extract('Customer Goal:', ['Resolution Status:'])
);

const resolution_status = normalizeStatus(
  extract('Resolution Status:', ['Agent Performance Notes:'])
);

const agent_performance_notes = sanitizeText(
  extract('Agent Performance Notes:', ['Agent Improvement Opportunities:'])
) || 'Unclear';

const agent_improvement_opportunities = sanitizeText(
  extract('Agent Improvement Opportunities:', ['Knowledge Base Opportunity:'])
) || 'None';

const kb_flag = normalizeYesNo(
  extract('Knowledge Base Opportunity:', ['Knowledge Base Opportunity Detail:'])
);

const kb_detail = sanitizeText(
  extract('Knowledge Base Opportunity Detail:', ['Automation Opportunity:'])
) || (kb_flag === 'Yes' ? 'Recommendation present but not parsed cleanly' : 'None');

const automation_flag = normalizeYesNo(
  extract('Automation Opportunity:', ['Automation Opportunity Detail:'])
);

const automation_detail = sanitizeText(
  extract('Automation Opportunity Detail:', ['Suggested Opportunity Type:'])
) || (automation_flag === 'Yes' ? 'Recommendation present but not parsed cleanly' : 'None');

const suggested_opportunity_type = normalizeOpportunityType(
  extract('Suggested Opportunity Type:', ['Key Tags:'])
);

const key_tags = cleanTags(
  extract('Key Tags:')
);

return {
  json: {
    analysis_batch_id: source.analysis_batch_id,
    form_id: source.form_id,
    form_name: source.form_name,
    date_from: source.date_from,
    date_to: source.date_to,

    ticket_id: source.ticket_id,
    issue_summary,
    root_cause_category,
    root_cause_detail,
    customer_goal,
    resolution_status,
    agent_performance_notes,
    agent_improvement_opportunities,
    knowledge_base_opportunity: kb_flag,
    knowledge_base_opportunity_detail: kb_detail,
    automation_opportunity: automation_flag,
    automation_opportunity_detail: automation_detail,
    suggested_opportunity_type,
    key_tags,

    prompt_tokens: $json.usage?.prompt_tokens || 0,
    completion_tokens: $json.usage?.completion_tokens || 0,
    total_tokens: $json.usage?.total_tokens || 0,

    created_at: source.created_at || new Date().toISOString()
  }
};

const items = $input.all();
const request = $('Prepare Analysis Request').first().json;

const ticket_results = items.map(item => {
  const r = item.json || {};
  return {
    ticket_id: r.ticket_id,
    issue_summary: r.issue_summary || 'Unclear',
    root_cause_category: r.root_cause_category || 'Unclear',
    root_cause_detail: r.root_cause_detail || 'Unclear',
    customer_goal: r.customer_goal || 'Unclear',
    resolution_status: r.resolution_status || 'Unclear',
    agent_performance_notes: r.agent_performance_notes || 'Unclear',
    agent_improvement_opportunities: r.agent_improvement_opportunities || 'None',
    knowledge_base_opportunity: r.knowledge_base_opportunity || 'Unclear',
    knowledge_base_opportunity_detail: r.knowledge_base_opportunity_detail || 'None',
    automation_opportunity: r.automation_opportunity || 'Unclear',
    automation_opportunity_detail: r.automation_opportunity_detail || 'None',
    suggested_opportunity_type: r.suggested_opportunity_type || 'Product Improvement',
    key_tags: r.key_tags || '',
    prompt_tokens: Number(r.prompt_tokens || 0),
    completion_tokens: Number(r.completion_tokens || 0),
    total_tokens: Number(r.total_tokens || 0),
    created_at: r.created_at || null
  };
});

return [{
  json: {
    analysis_batch_id: request.analysis_batch_id,
    form_id: request.form_id,
    form_name: request.form_name,
    date_from: request.date_from,
    date_to: request.date_to,
    total_tickets: ticket_results.length,
    analyzed_count: ticket_results.length,
    ticket_results
  }
}];

const raw = $json.output_text || $json.text || $json.response || '';
const request = $('Prepare Analysis Request').first().json;
const batchInput = $('Build Batch Group Input').first().json;

function tryParseJson(text) {
  if (typeof text !== 'string') return null;

  const trimmed = text.trim();

  try {
    return JSON.parse(trimmed);
  } catch (e) {}

  const fencedMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fencedMatch) {
    try {
      return JSON.parse(fencedMatch[1].trim());
    } catch (e) {}
  }

  const firstBrace = trimmed.indexOf('{');
  const lastBrace = trimmed.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    const candidate = trimmed.slice(firstBrace, lastBrace + 1);
    try {
      return JSON.parse(candidate);
    } catch (e) {}
  }

  return null;
}

function sanitizeText(value) {
  return String(value || '')
    .replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, '[REDACTED_EMAIL]')
    .replace(/https?:\/\/\S+/gi, '[REDACTED_URL]')
    .replace(/\+?\d[\d\-\(\) ]{7,}\d/g, '[REDACTED_PHONE]')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeYesNo(value) {
  const v = sanitizeText(value).toLowerCase();
  if (v === 'yes' || v.startsWith('yes')) return 'Yes';
  return 'No';
}

function normalizeOpportunityType(value) {
  const cleaned = sanitizeText(value);
  if (cleaned === 'Knowledge Base') return 'Knowledge Base';
  if (cleaned === 'Process Update') return 'Process Update';
  if (cleaned === 'Agent Training') return 'Agent Training';
  if (cleaned === 'Product Improvement') return 'Product Improvement';
  return 'Process Update';
}

function slugify(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

const parsed = tryParseJson(raw);

if (!parsed) {
  throw new Error('Parse Batch Grouping: LLM2 did not return valid JSON.');
}

const originalResultsByTicketId = new Map(
  (batchInput.ticket_results || []).map(r => [String(r.ticket_id), r])
);

const normalized_results = Array.isArray(parsed.normalized_results)
  ? parsed.normalized_results
      .map(r => {
        const ticketId = r.ticket_id;
        const original = originalResultsByTicketId.get(String(ticketId));
        if (!original) return null;

        const normalized_tags = Array.isArray(r.normalized_tags)
          ? r.normalized_tags
              .map(t => sanitizeText(t))
              .filter(Boolean)
              .slice(0, 5)
          : [];

        return {
          ticket_id: original.ticket_id,
          issue_summary: original.issue_summary,
          root_cause_category: original.root_cause_category,
          root_cause_detail: original.root_cause_detail,
          customer_goal: original.customer_goal,
          resolution_status: original.resolution_status,
          agent_performance_notes: original.agent_performance_notes,
          agent_improvement_opportunities: original.agent_improvement_opportunities,
          knowledge_base_opportunity: normalizeYesNo(r.knowledge_base_opportunity),
          knowledge_base_opportunity_detail: sanitizeText(r.knowledge_base_opportunity_detail) || 'None',
          automation_opportunity: original.automation_opportunity,
          automation_opportunity_detail: original.automation_opportunity_detail,
          suggested_opportunity_type: original.suggested_opportunity_type,
          opportunity_type: normalizeOpportunityType(r.opportunity_type),
          key_tags: normalized_tags.join(', '),
          normalized_tags,
          prompt_tokens: original.prompt_tokens || 0,
          completion_tokens: original.completion_tokens || 0,
          total_tokens: original.total_tokens || 0,
          created_at: original.created_at || null
        };
      })
      .filter(Boolean)
  : [];

const allowedCategories = new Set(
  normalized_results.map(r => r.root_cause_category)
);

const opportunity_groups = Array.isArray(parsed.opportunity_groups)
  ? parsed.opportunity_groups
      .map(g => {
        const ticketIds = Array.isArray(g.zendesk_ticket_ids)
          ? g.zendesk_ticket_ids.filter(id => originalResultsByTicketId.has(String(id)))
          : [];

        const rootCauseCategory = sanitizeText(g.root_cause_category);
        const safeCategory = allowedCategories.has(rootCauseCategory)
          ? rootCauseCategory
          : 'Unclear';

        return {
          group_key: sanitizeText(g.group_key) || slugify(`${g.opportunity_type || 'group'}-${g.title || 'group'}`),
          title: sanitizeText(g.title) || 'Untitled Opportunity Group',
          opportunity_type: normalizeOpportunityType(g.opportunity_type),
          root_cause_category: safeCategory,
          summary: sanitizeText(g.summary) || 'Recurring support pattern detected.',
          recommended_next_step: sanitizeText(g.recommended_next_step) || 'Review this recurring issue pattern and define the next operational action.',
          linked_ticket_count: [...new Set(ticketIds)].length,
          zendesk_ticket_ids: [...new Set(ticketIds)]
        };
      })
      .filter(g => g.zendesk_ticket_ids.length > 0)
  : [];

const heatmap_rows = Array.isArray(parsed.heatmap_rows)
  ? parsed.heatmap_rows.map(h => ({
      root_cause_category: allowedCategories.has(sanitizeText(h.root_cause_category))
        ? sanitizeText(h.root_cause_category)
        : 'Unclear',
      form_name: sanitizeText(h.form_name) || request.form_name || 'Unknown Form',
      ticket_count: Number(h.ticket_count || 0)
    }))
  : [];

return {
  json: {
    analysis_batch_id: request.analysis_batch_id,
    form_id: request.form_id,
    form_name: request.form_name,
